{{state_descriptions}}: {{
  "order_id": "Unique identifier for the customer order.",
  "order_status": "The current lifecycle stage of the order (e.g., 'delivered', 'return_pending', 'returned', 'refunded').",
  "delivery_date": "ISO 8601 formatted date of when the order was delivered to the customer.",
  "return_window_days": "The number of days allowed for a return after the delivery date.",
  "items": "List of products in the order, including their SKU and condition.",
  "refund_total": "The amount of money currently processed for refund.",
  "authorization_code": "The unique RMA (Return Merchandise Authorization) code if a return has been approved."
}}
{action_set_definitions}: {
  "get_order_details": {
    "description": "Retrieves the full details of an order including status, items (with SKUs), delivery dates, and return window eligibility.",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "The unique identifier of the order (e.g., ORD-8829-HZ)."
        }
      },
      "required": [
        "order_id"
      ]
    },
    "example_output": {
      "order_id": "ORD-8829-HZ",
      "items": [
        {
          "sku": "VM-5000-BLK",
          "name": "VoltMaster 5000 Power Station",
          "quantity": 1
        }
      ],
      "delivery_date": "2023-10-01",
      "return_window_days": 30,
      "order_status": "delivered"
    }
  },
  "submit_hazmat_safety_triage": {
    "description": "Records the safety assessment for damaged hazardous materials (specifically lithium-ion batteries) to determine transport viability and necessary safety protocols.",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "The unique identifier of the order."
        },
        "sku": {
          "type": "string",
          "description": "The SKU of the damaged item."
        },
        "damage_type": {
          "type": "string",
          "enum": [
            "cracked_chassis",
            "punctured_cell",
            "swollen_casing",
            "external_dent"
          ],
          "description": "The specific type of physical damage."
        },
        "is_leaking": {
          "type": "boolean",
          "description": "Whether any fluid or electrolyte leakage is observed."
        },
        "is_smoking": {
          "type": "boolean",
          "description": "Whether any smoke or heat generation is observed."
        }
      },
      "required": [
        "order_id",
        "sku",
        "damage_type",
        "is_leaking",
        "is_smoking"
      ]
    },
    "example_output": {
      "triage_id": "TRG-9921",
      "safety_class": "Damaged/Defective Lithium Battery (DDR)",
      "transport_allowed": true,
      "required_packaging": "UN-certified metal drum with vermiculite insulation"
    }
  },
  "authorize_return_with_hazmat_label": {
    "description": "Finalizes the return process by generating an RMA code and issuing specialized hazardous material shipping instructions/labels based on the safety triage.",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "The unique identifier of the order."
        },
        "triage_id": {
          "type": "string",
          "description": "The ID from the completed safety triage."
        },
        "shipping_method": {
          "type": "string",
          "description": "The specialized carrier or method required (e.g., Ground-Only Specialized Hazmat)."
        },
        "refund_amount": {
          "type": "number",
          "description": "The total amount to be authorized for refund upon receipt."
        }
      },
      "required": [
        "order_id",
        "triage_id",
        "shipping_method",
        "refund_amount"
      ]
    },
    "example_output": {
      "authorization_code": "RMA-772-B",
      "status": "return_authorized",
      "label_type": "Hazmat Class 9 - Ground"
    }
  }
}
